7746	\begin{lemma}[Pullback along an open immersion is the restriction functor]
7747	  \label{lem:restrictFunctorIsoPullback_mathlib}
7748	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctorIsoPullback}
7749	  \mathlibok
7750	  \textit{Provided by Mathlib.}
7751	  For an open immersion \(f : X \to Y\), the restriction functor
7752	  \(\operatorname{restrictFunctor} f : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) is
7753	  naturally isomorphic to the module pullback functor \(f^* = \operatorname{pullback} f\). In
7754	  particular \(f^*\mathcal{M} \cong \mathcal{M}.\operatorname{restrict} f\) for every
7755	  \(\mathcal{O}_Y\)-module \(\mathcal{M}\).
7756	\end{lemma}
