7758	\begin{lemma}[Evaluation of a sheaf of modules preserves products]
7759	  \label{lem:evaluation_preserves_products_mathlib}
7760	  \lean{SheafOfModules.evaluationPreservesLimitsOfShape}
7761	  \mathlibok
7762	  \textit{Provided by Mathlib.}
7763	  For a sheaf of rings on a site and any object \(U\), the evaluation (sections-at-\(U\))
7764	  functor \(\operatorname{evaluation}\,U : \operatorname{SheafOfModules} \to \mathrm{Ab}\)
7765	  preserves limits of every shape; in particular it preserves products, so \(\Gamma(U,
7766	  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(U, N_\sigma)\).
7767	\end{lemma}
7768	
7769	\begin{lemma}[Sections over a binary coproduct scheme are a product]
7770	  \label{lem:coprodPresheafObjIso_mathlib}
7771	  \lean{AlgebraicGeometry.Scheme.coprodPresheafObjIso}
7772	  \mathlibok
7773	  \textit{Provided by Mathlib.}
7774	  For schemes \(X, Y\) and an open \(U\) of the coproduct \(X \amalg Y\), the structure-sheaf
7775	  sections over \(U\) decompose as the product of the sections over the two preimages:
7776	  \((X \amalg Y).\mathcal{O}(U) \cong X.\mathcal{O}(\operatorname{inl}^{-1} U) \times
7777	  Y.\mathcal{O}(\operatorname{inr}^{-1} U)\). This is the binary disjoint-union sheaf
7778	  decomposition that Lemma~\ref{lem:pushPull_sigma_iso} ports to the indexed,
7779	  \(\operatorname{SheafOfModules}\) setting.
7780	\end{lemma}
